AND (
  LOWER(title) LIKE #{keyword}
  OR LOWER(content) LIKE #{keyword}
  OR LOWER(answer) LIKE #{keyword}
  OR LOWER(tags_json) LIKE #{keyword}
  OR LOWER(category) LIKE #{keyword}
