mapper.select:
SELECT

FROM interview_question
WHERE enabled = TRUE

ORDER BY updated_at DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT

FROM interview_question
WHERE enabled = TRUE

  AND CASE WHEN bank_type = 'leetcode' THEN 'leetcode' ELSE 'qa' END = #{bankType}


  AND category = #{category}


  AND difficulty = #{difficulty}


  AND question_type = #{questionType}

ORDER BY updated_at DESC

SELECT DISTINCT category FROM interview_question WHERE enabled = TRUE AND category IS NOT NULL AND category != ''
AND CASE WHEN bank_type = 'leetcode' THEN 'leetcode' ELSE 'qa' END = #{bankType}
ORDER BY category ASC

SELECT DISTINCT difficulty FROM interview_question WHERE enabled = TRUE AND difficulty IS NOT NULL AND difficulty != ''
AND CASE WHEN bank_type = 'leetcode' THEN 'leetcode' ELSE 'qa' END = #{bankType}
ORDER BY difficulty ASC

SELECT DISTINCT question_type FROM interview_question WHERE enabled = TRUE AND question_type IS NOT NULL AND question_type != ''
AND CASE WHEN bank_type = 'leetcode' THEN 'leetcode' ELSE 'qa' END = #{bankType}
ORDER BY question_type ASC

SELECT COUNT(*)
FROM interview_question
WHERE question_id = #{questionId}

mapper.update:
UPDATE interview_question
SET
  enabled = FALSE,
  updated_at = #{updatedAt}
WHERE question_id = #{questionId}

UPDATE interview_question
SET category = #{category}, updated_at = #{updatedAt}
WHERE question_id = #{questionId}

UPDATE interview_question
SET difficulty = #{difficulty}, updated_at = #{updatedAt}
WHERE question_id = #{questionId}

UPDATE interview_question
SET tags_json = #{tagsJson}, updated_at = #{updatedAt}
WHERE question_id = #{questionId}

